INSERT INTO Movies (MovieID, Title, PosterURL, StreamingServices, Genre, Rating, Description, Actors) VALUES
('tt0012349', 'The Kid', 'Poster URL', 'The Criterion Channel', 'Comedy', 8.3, 'A pompous millionaire finds his carefree existence turned upside down when a resourceful young orphan enters his life and refuses to leave.', 'Charlie Chaplin, Jackie Coogan, Edna Purviance'),
('tt0027977', 'Modern Times', 'Poster URL', 'The Criterion Channel', 'Romance', 8.5, 'A factory worker struggles to survive the pressures of industrial life while falling for a homeless young woman, together searching for a better future.', 'Charlie Chaplin, Paulette Goddard, Henry Bergman'),
('tt0034583', 'Casablanca', 'Poster URL', 'Amazon Prime Video', 'Drama', 8.5, 'In wartime Morocco, a cynical American nightclub owner must choose between love and virtue when his former lover arrives with her fugitive husband seeking transit papers.', 'Humphrey Bogart, Ingrid Bergman, Paul Henreid'),
('tt0038650', 'It''s a Wonderful Life', 'Poster URL', 'Amazon Prime Video', 'Family', 8.6, 'A despairing small-town man is granted the chance to see what life would have been like for his community had he never been born, guided by his bumbling guardian angel.', 'James Stewart, Donna Reed, Lionel Barrymore'),
('tt0047396', 'Rear Window', 'Poster URL', 'Amazon Prime Video', 'Thriller', 8.5, 'A photographer confined to a wheelchair becomes convinced he has witnessed a murder through his apartment window, drawing his girlfriend into a dangerous investigation.', 'James Stewart, Grace Kelly, Wendell Corey'),
('tt0051201', 'Witness for the Prosecution', 'Poster URL', 'Amazon Prime Video', 'Crime', 8.4, 'A brilliant but ailing barrister takes on the seemingly unwinnable case of a man accused of murder, only to be blindsided by shocking courtroom revelations.', 'Tyrone Power, Marlene Dietrich, Charles Laughton'),
('tt0054215', 'Psycho', 'Poster URL', 'Peacock', 'Horror', 8.5, 'A secretary on the run with stolen money checks into a remote motel run by a peculiar young man dominated by his mysterious mother, with terrifying consequences.', 'Anthony Perkins, Janet Leigh, Vera Miles'),
('tt0057012', 'Dr. Strangelove', 'Poster URL', 'Amazon Prime Video', 'War', 8.4, 'A deranged general triggers a nuclear crisis that sets off a chain of absurd events, leaving the President and his advisors scrambling to avert World War III.', 'Peter Sellers, George C. Scott, Sterling Hayden'),
('tt0060196', 'The Good, the Bad and the Ugly', 'Poster URL', 'Pluto TV', 'Adventure', 8.8, 'Three gunslingers compete in a dangerous race across the American Southwest to find a buried cache of Confederate gold during the Civil War.', 'Clint Eastwood, Lee Van Cleef, Eli Wallach'),
('tt0068646', 'The Godfather', 'Poster URL', 'Paramount+', 'Crime', 9.2, 'The aging patriarch of an organized crime dynasty transfers control of his empire to his reluctant son, sparking a bloody war among the New York Mafia families.', 'Marlon Brando, Al Pacino, James Caan'),
('tt0071562', 'The Godfather Part II', 'Poster URL', 'Paramount+', 'Crime', 9.0, 'The rise of a young Vito Corleone in early 20th-century New York unfolds in parallel with his son Michael''s ruthless consolidation of the family''s criminal empire.', 'Al Pacino, Robert De Niro, Robert Duvall'),
('tt0073195', 'Jaws', 'Poster URL', 'Peacock', 'Thriller', 8.1, 'A small beach town is terrorized by a massive great white shark, forcing the local police chief, a marine biologist, and a grizzled shark hunter to join forces.', 'Roy Scheider, Robert Shaw, Richard Dreyfuss'),
('tt0073486', 'One Flew Over the Cuckoo''s Nest', 'Poster URL', 'Amazon Prime Video', 'Drama', 8.7, 'A free-spirited man fakes insanity to serve his prison sentence in a mental institution, where he clashes with the iron-fisted Nurse Ratched and inspires his fellow patients.', 'Jack Nicholson, Louise Fletcher, Brad Dourif'),
('tt0080684', 'Star Wars: Episode V - The Empire Strikes Back', 'Poster URL', 'Disney+', 'Action', 8.7, 'After the Rebel Alliance suffers a devastating defeat, Luke Skywalker trains with the legendary Yoda while his friends are hunted across the galaxy by Darth Vader.', 'Mark Hamill, Harrison Ford, Carrie Fisher'),
('tt0081505', 'The Shining', 'Poster URL', 'Max', 'Horror', 8.4, 'A writer becomes the winter caretaker of an isolated mountain hotel, where supernatural forces and cabin fever drive him to terrifying madness, threatening his family.', 'Jack Nicholson, Shelley Duvall, Danny Lloyd'),
('tt0086250', 'Scarface', 'Poster URL', 'Amazon Prime Video', 'Crime', 8.3, 'A Cuban refugee arrives in Miami with nothing and claws his way to the top of the cocaine trade, only to see his empire crumble under the weight of his paranoia and excess.', 'Al Pacino, Michelle Pfeiffer, Steven Bauer'),
('tt0088763', 'Back to the Future', 'Poster URL', 'Amazon Prime Video', 'Sci-Fi', 8.5, 'A teenager is accidentally sent back to 1955 in a time-traveling DeLorean and must ensure his parents fall in love while finding a way back to the future.', 'Michael J. Fox, Christopher Lloyd, Lea Thompson'),
('tt0090605', 'Aliens', 'Poster URL', 'Amazon Prime Video', 'Sci-Fi', 8.4, 'Ripley returns to the moon where her crew first encountered the deadly xenomorphs, this time accompanied by a unit of marines who are in for the fight of their lives.', 'Sigourney Weaver, Michael Biehn, Bill Paxton'),
('tt0093779', 'The Princess Bride', 'Poster URL', 'Disney+', 'Adventure', 8.0, 'A bedridden boy listens to his grandfather read a fairy tale about a farmhand-turned-pirate who races to rescue his one true love from a villainous prince.', 'Cary Elwes, Robin Wright, Mandy Patinkin'),
('tt0095016', 'Die Hard', 'Poster URL', 'Amazon Prime Video', 'Action', 8.2, 'A New York cop visiting his estranged wife in Los Angeles becomes the only hope for hostages when a group of terrorists seize a Nakatomi Plaza skyscraper on Christmas Eve.', 'Bruce Willis, Alan Rickman, Bonnie Bedelia'),
('tt0095067', 'Eight Crazy Nights', 'Poster URL', 'Hulu', 'Comedy', 6.7, 'An animated Hanukkah musical comedy following a party-hard slacker who is sentenced to community service as a youth basketball referee under a kindhearted but eccentric volunteer.', 'Adam Sandler, Jackie Titone, Austin Stout'),
('tt0095327', 'Grave of the Fireflies', 'Poster URL', 'Netflix', 'Animation', 8.5, 'In the final months of World War II, a teenage boy struggles to care for his younger sister after they are orphaned by American firebombing raids in Japan.', 'Tsutomu Tatsumi, Ayano Shiraishi, Akemi Yamaguchi'),
('tt0095765', 'Cinema Paradiso', 'Poster URL', 'Amazon Prime Video', 'Drama', 8.5, 'A celebrated film director reflects on his childhood in postwar Sicily, where a projectionist at the local cinema became a father figure who shaped his lifelong love of movies.', 'Philippe Noiret, Enzo Cannavale, Antonella Attili'),
('tt0095953', 'Rain Man', 'Poster URL', 'Pluto TV', 'Drama', 8.0, 'A self-centered car dealer discovers he has a brother — an autistic savant — and kidnaps him from an institution in hopes of claiming his inheritance, leading to an unexpected cross-country bond.', 'Dustin Hoffman, Tom Cruise, Valeria Golino'),
('tt0097165', 'Dead Poets Society', 'Poster URL', 'Disney+', 'Drama', 8.1, 'An unconventional English teacher at a prestigious prep school inspires his students to seize the day through poetry and free thought, with life-altering consequences.', 'Robin Williams, Robert Sean Leonard, Ethan Hawke'),
('tt0097576', 'Indiana Jones and the Last Crusade', 'Poster URL', 'Amazon Prime Video', 'Action', 8.2, 'Archaeologist Indiana Jones teams up with his estranged father to race against the Nazis in a globe-trotting search for the legendary Holy Grail.', 'Harrison Ford, Sean Connery, Denholm Elliott'),
('tt0099685', 'Goodfellas', 'Poster URL', 'Max', 'Biography', 8.7, 'The true story of Henry Hill, who grows up in a mob family and works his way up through the criminal underworld, until drugs, paranoia, and betrayal lead to his downfall.', 'Ray Liotta, Robert De Niro, Joe Pesci'),
('tt0101414', 'Beauty and the Beast', 'Poster URL', 'Disney+', 'Fantasy', 8.0, 'A bright young woman is taken prisoner by a fearsome enchanted Beast in his magical castle and begins to see beyond his monstrous exterior to the man hidden within.', 'Paige O''Hara, Robby Benson, Jerry Orbach'),
('tt0102926', 'The Silence of the Lambs', 'Poster URL', 'Hulu', 'Thriller', 8.6, 'An FBI trainee seeks the help of the brilliant but terrifyingly manipulative cannibalistic psychiatrist Hannibal Lecter to catch a serial killer who skins his victims.', 'Jodie Foster, Anthony Hopkins, Scott Glenn'),
('tt0103064', 'Terminator 2: Judgment Day', 'Poster URL', 'Amazon Prime Video', 'Sci-Fi', 8.6, 'A reprogrammed Terminator is sent back in time to protect teenage John Connor from a more advanced and lethal shape-shifting machine bent on his destruction.', 'Arnold Schwarzenegger, Linda Hamilton, Edward Furlong'),
('tt0105236', 'Reservoir Dogs', 'Poster URL', 'Amazon Prime Video', 'Thriller', 8.3, 'After a diamond heist goes violently wrong, the surviving criminals hole up in a warehouse and try to figure out which one of them is the police informant.', 'Harvey Keitel, Tim Roth, Michael Madsen'),
('tt0105695', 'Unforgiven', 'Poster URL', 'Max', 'Western', 8.2, 'A retired outlaw takes on one last job alongside his old partner and a young gunfighter to collect a bounty on two cowboys who mutilated a prostitute.', 'Clint Eastwood, Gene Hackman, Morgan Freeman'),
('tt0107048', 'Groundhog Day', 'Poster URL', 'Netflix', 'Drama', 8.0, 'A cynical TV weatherman finds himself inexplicably reliving the same small-town Groundhog Day over and over, forced to examine his life and find meaning in the loop.', 'Bill Murray, Andie MacDowell, Chris Elliott'),
('tt0107290', 'Jurassic Park', 'Poster URL', 'Peacock', 'Sci-Fi', 8.2, 'A billionaire''s dream of cloning dinosaurs for a theme park turns into a nightmare when the prehistoric predators break free and begin hunting the stranded visitors.', 'Sam Neill, Laura Dern, Jeff Goldblum'),
('tt0108052', 'Schindler''s List', 'Poster URL', 'Peacock', 'History', 9.0, 'Based on the true story of Oskar Schindler, a German industrialist who saved the lives of more than a thousand Jewish refugees during the Holocaust by employing them in his factories.', 'Liam Neeson, Ben Kingsley, Ralph Fiennes'),
('tt0109830', 'Forrest Gump', 'Poster URL', 'Paramount+', 'Romance', 8.8, 'A kind-hearted man from Alabama with a low IQ inadvertently witnesses and influences many defining moments in 20th-century American history while searching for his childhood love.', 'Tom Hanks, Robin Wright, Gary Sinise'),
('tt0110357', 'The Lion King', 'Poster URL', 'Disney+', 'Animation', 8.5, 'A young lion prince flees his kingdom after the murder of his father and must find the courage to return, claim his throne, and face his treacherous uncle.', 'Matthew Broderick, Jeremy Irons, James Earl Jones'),
('tt0110912', 'Pulp Fiction', 'Poster URL', 'Paramount+', 'Crime', 8.9, 'The lives of two mob hitmen, a boxer, a gangster, and a pair of diner bandits intertwine in four tales of violence and redemption in Los Angeles.', 'John Travolta, Uma Thurman, Samuel L. Jackson'),
('tt0111161', 'The Shawshank Redemption', 'Poster URL', 'Max', 'Drama', 9.3, 'An innocent banker is sentenced to life in Shawshank Prison and forms an unlikely friendship with a seasoned inmate, finding hope and redemption through sheer perseverance.', 'Tim Robbins, Morgan Freeman, Bob Gunton'),
('tt0118799', 'Life Is Beautiful', 'Poster URL', 'Pluto TV', 'Romance', 8.6, 'A charming Jewish Italian man uses his imagination and humor to shield his young son from the horrors of a Nazi concentration camp by convincing him it is all an elaborate game.', 'Roberto Benigni, Nicoletta Braschi, Giorgio Cantarini'),
('tt0120601', 'Being John Malkovich', 'Poster URL', 'Amazon Prime Video', 'Comedy', 7.7, 'A struggling puppeteer discovers a mysterious portal that leads directly into the mind of movie star John Malkovich, sparking an identity-bending obsession.', 'John Cusack, Cameron Diaz, John Malkovich'),
('tt0120737', 'The Lord of the Rings: The Fellowship of the Ring', 'Poster URL', 'Max', 'Adventure', 8.8, 'A young hobbit embarks on an epic quest to destroy a powerful and corrupting ring, accompanied by a fellowship of heroes against the growing darkness of an ancient evil.', 'Elijah Wood, Ian McKellen, Viggo Mortensen'),
('tt0120815', 'Saving Private Ryan', 'Poster URL', 'Paramount+', 'War', 8.6, 'Following the Normandy invasion, a captain leads a squad of soldiers deep behind enemy lines on a dangerous mission to find and bring home a paratrooper whose brothers have all been killed in action.', 'Tom Hanks, Tom Sizemore, Matt Damon'),
('tt0133093', 'The Matrix', 'Poster URL', 'Max', 'Action', 8.7, 'A computer hacker learns the world he lives in is a simulated reality created by machines, and joins a rebellion of freed humans fighting to overthrow their captors.', 'Keanu Reeves, Laurence Fishburne, Carrie-Anne Moss'),
('tt0137523', 'Fight Club', 'Poster URL', 'Amazon Prime Video', 'Drama', 8.8, 'An insomniac office worker forms an underground fight club with a charismatic soap salesman, which evolves into something far more dangerous and anarchic than either man imagined.', 'Brad Pitt, Edward Norton, Helena Bonham Carter'),
('tt0167260', 'The Lord of the Rings: The Return of the King', 'Poster URL', 'Amazon Prime Video', 'Adventure', 8.9, 'Aragorn leads the forces of Middle-earth against the armies of Sauron in a final battle to distract the Dark Lord while Frodo and Sam make their last desperate push to destroy the One Ring.', 'Elijah Wood, Viggo Mortensen, Ian McKellen'),
('tt0209144', 'Memento', 'Poster URL', 'Amazon Prime Video', 'Mystery', 8.4, 'A man suffering from anterograde amnesia uses tattoos and Polaroid photos to track down the man he believes murdered his wife, piecing together a mystery the audience experiences in reverse.', 'Guy Pearce, Carrie-Anne Moss, Joe Pantoliano'),
('tt0317248', 'City of God', 'Poster URL', 'Amazon Prime Video', 'Crime', 8.6, 'A young photographer chronicles the brutal rise of organized crime in Rio de Janeiro''s most dangerous favela during the 1960s and 70s, striving to escape the violence around him.', 'Alexandre Rodrigues, Leandro Firmino, Phellipe Haagensen'),
('tt0364569', 'Oldboy', 'Poster URL', 'Netflix', 'Action', 8.4, 'A man imprisoned in a cell for 15 years without explanation is suddenly released and given five days to find out who imprisoned him — and why — uncovering a devastating truth.', 'Choi Min-sik, Yoo Ji-tae, Kang Hye-jung'),
('tt0407887', 'The Departed', 'Poster URL', 'Netflix', 'Thriller', 8.5, 'In Boston, an undercover cop infiltrates the Irish mob while a mole within the police force reports back to the gang leaders, each racing to expose the other before being discovered.', 'Leonardo DiCaprio, Matt Damon, Jack Nicholson'),
('tt0468569', 'The Dark Knight', 'Poster URL', 'Max', 'Action', 9.0, 'Batman faces his greatest threat when a criminal mastermind known as the Joker rises from the Gotham underworld and plunges the city into anarchy, testing the hero''s moral limits.', 'Christian Bale, Heath Ledger, Aaron Eckhart'),
('tt0816692', 'Interstellar', 'Poster URL', 'Paramount+', 'Sci-Fi', 8.7, 'A former NASA pilot leads a crew of astronauts through a wormhole near Saturn in search of a new habitable planet as Earth faces environmental collapse, leaving his family behind.', 'Matthew McConaughey, Anne Hathaway, Jessica Chastain'),
('tt1375666', 'Inception', 'Poster URL', 'Amazon Prime Video', 'Action', 8.8, 'A skilled thief who specializes in stealing secrets from people''s dreams is offered a chance to have his criminal record erased if he can successfully plant an idea in a target''s subconscious.', 'Leonardo DiCaprio, Joseph Gordon-Levitt, Elliot Page'),
('tt1675434', 'The Intouchables', 'Poster URL', 'Netflix', 'Biography', 8.5, 'A wealthy French aristocrat paralyzed from the neck down forms an unlikely and life-changing friendship with an irreverent young man from the projects hired to be his caretaker.', 'François Cluzet, Omar Sy, Anne Le Ny'),
('tt2119532', 'Hacksaw Ridge', 'Poster URL', 'Amazon Prime Video', 'War', 8.1, 'The true story of Desmond Doss, a conscientious objector who refused to carry a weapon but served as a combat medic in World War II and single-handedly saved 75 men at the Battle of Okinawa.', 'Andrew Garfield, Sam Worthington, Luke Bracey'),
('tt2380307', 'Coco', 'Poster URL', 'Disney+', 'Family', 8.4, 'A young aspiring musician is transported to the Land of the Dead on Día de Muertos, where he embarks on an extraordinary journey to find his great-great-grandfather and uncover his family''s history.', 'Anthony Gonzalez, Gael García Bernal, Benjamin Bratt'),
('tt2582802', 'Whiplash', 'Poster URL', 'Netflix', 'Drama', 8.5, 'An ambitious young jazz drummer at a prestigious music conservatory is pushed to his mental and physical limits by a ruthless, manipulative conductor obsessed with perfection.', 'Miles Teller, J.K. Simmons, Melissa Benoist'),
('tt8267604', 'Parasite', 'Poster URL', 'Hulu', 'Comedy', 8.5, 'A poor Korean family schemes to become employed by a wealthy household, but their plan takes a dark and shocking turn when an unexpected secret is discovered beneath the mansion.', 'Song Kang-ho, Lee Sun-kyun, Cho Yeo-jeong');
INSERT INTO Reviews (ReviewID, MovieID, UserID, Score, Text) VALUES
('rev_001', 'tt0111161', 'user_035', 10, 'A perfect film in every way. The storytelling, acting, and emotional depth are unmatched.'),
('rev_002', 'tt0468569', 'user_012', 9, 'Heath Ledger''s performance is legendary. The tension throughout keeps you on edge.'),
('rev_003', 'tt1375666', 'user_028', 8, 'Mind-bending concept executed brilliantly. Takes multiple viewings to fully appreciate.'),
('rev_004', 'tt0099685', 'user_005', 9, 'Scorsese at his finest. The energy and dialogue are electric from start to finish.'),
('rev_005', 'tt0109830', 'user_041', 7, 'A heartwarming journey through American history. Hanks delivers another great performance.'),
('rev_006', 'tt0068646', 'user_019', 10, 'The greatest American film ever made. Every scene is iconic and perfectly crafted.'),
('rev_007', 'tt0137523', 'user_023', 9, 'The twist still catches me off guard even after multiple watches. So thought-provoking.'),
('rev_008', 'tt0120737', 'user_002', 9, 'A breathtaking start to the trilogy. The world-building is extraordinary.'),
('rev_009', 'tt0081505', 'user_016', 8, 'Kubrick''s direction creates an unsettling atmosphere that stays with you.'),
('rev_010', 'tt0108052', 'user_008', 10, 'Devastating and essential viewing. A powerful reminder of humanity''s darkest chapter.'),
('rev_011', 'tt0110912', 'user_031', 9, 'Tarantino''s dialogue is unmatched. The nonlinear structure keeps it fresh every time.'),
('rev_012', 'tt0167260', 'user_044', 10, 'An epic conclusion to an epic saga. The battle sequences are cinema at its best.'),
('rev_013', 'tt0071562', 'user_011', 9, 'A rare sequel that matches the original. Michael''s descent into darkness is compelling.'),
('rev_014', 'tt0133093', 'user_027', 8, 'Revolutionary for its time. The bullet time scenes changed action films forever.'),
('rev_015', 'tt0102926', 'user_038', 9, 'Hopkins is terrifying as Lecter. A masterclass in building suspense.'),
('rev_016', 'tt0054215', 'user_003', 8, 'Hitchcock''s masterpiece. The shower scene still holds up after all these years.'),
('rev_017', 'tt0097576', 'user_045', 7, 'A fun adventure with great chemistry between Ford and Connery.'),
('rev_018', 'tt0088763', 'user_022', 9, 'Pure joy from beginning to end. The DeLorean is one of cinema''s great icons.'),
('rev_019', 'tt0110357', 'user_048', 8, 'Beautiful animation and unforgettable songs. It still makes me emotional.'),
('rev_020', 'tt0120815', 'user_009', 9, 'The opening D-Day sequence is gut-wrenching. A powerful tribute to the Greatest Generation.'),
('rev_021', 'tt0080684', 'user_014', 9, 'The best Star Wars film. The revelation about Vader is perfectly set up.'),
('rev_022', 'tt0103064', 'user_033', 8, 'Incredible effects for its time. The T-1000 is a terrifying villain.'),
('rev_023', 'tt0364569', 'user_026', 9, 'Brutal and unforgettable. The corridor fight scene is one of the best ever.'),
('rev_024', 'tt0038650', 'user_007', 8, 'A heartwarming classic that reminds us what''s truly important in life.'),
('rev_025', 'tt0057012', 'user_039', 8, 'The darkest comedy ever made. Peter Sellers is brilliant in multiple roles.'),
('rev_026', 'tt0047396', 'user_018', 8, 'Stewart and Grace Kelly are perfect together. The tension builds masterfully.'),
('rev_027', 'tt0095327', 'user_042', 9, 'Prepare to cry. The most heartbreaking animated film ever made.'),
('rev_028', 'tt0086250', 'user_004', 7, 'Pacino goes full Pacino. An iconic performance in an iconic film.'),
('rev_029', 'tt0209144', 'user_036', 9, 'Watching it backwards has never been so satisfying. Nolan''s indie masterpiece.'),
('rev_030', 'tt0090605', 'user_021', 8, 'Cameron knows how to raise the stakes. The queen reveal still gets me.'),
('rev_031', 'tt0051201', 'user_049', 8, 'A courtroom drama with a twist you won''t see coming. Absolutely brilliant.'),
('rev_048', 'tt1375666', 'user_043', 8, 'The spinning top at the end... I still debate whether he''s dreaming.'),
('rev_049', 'tt0099685', 'user_020', 8, 'Funny, violent, and stylish. Pesci steals every scene he''s in.')
